daimo:inputSchema.jsonSchema:
{
  "type": "object",
  "properties": {
    "Id": {
      "type": "integer",
      "description": "Input text identifier"
    },
    "Text": {
      "type": "string",
      "description": "Original Spanish text"
    },
    "5W1H_Label": {
      "type": "string",
      "description": "5W1H span label"
    },
    "Tag_Text": {
      "type": "string",
      "description": "Extracted span text"
    },
    "Tag_Start": {
      "type": "integer",
      "description": "Span start character offset"
    },
    "Tag_End": {
      "type": "integer",
      "description": "Span end character offset"
    },
    "Reliability_Label": {
      "type": "string",
      "description": "Gold reliability label"
    }
  },
  "required": [
    "Id",
    "Text",
    "5W1H_Label",
    "Tag_Text",
    "Tag_Start",
    "Tag_End",
    "Reliability_Label"
  ]
}
